<template><div class="resource-recommendation"><h2>PPT Generation</h2><p>AI-powered teaching slide generator</p><el-alert v-if="!apiAvailable" title="API not configured, using local mode" type="info" show-icon :closable="false"></el-alert><el-form><el-form-item label="Topic"><el-input v-model="searchForm.topic" placeholder="e.g. Database Systems"></el-input></el-form-item><el-form-item label="Subject"><el-select v-model="searchForm.subject" placeholder="Select"><el-option label="AI" value="ai"></el-option><el-option label="Python" value="python"></el-option><el-option label="ML" value="ml"></el-option><el-option label="CS" value="cs"></el-option></el-select></el-form-item><el-form-item label="Difficulty"><el-slider v-model="searchForm.difficulty" :min="1" :max="5"></el-slider></el-form-item><el-form-item><el-button type="primary" @click="generatePPT" :loading="searching">Generate PPT</el-button></el-form-item></el-form><h3>Recent</h3><div v-if="resources.length"><el-card v-for="r in resources" :key="r.id"><h4>{{r.title}}</h4><p>{{r.description}}</p></el-card></div></div></template><script>export default{name:'ResourceRecommendation',data(){return{searchForm:{topic:'',subject:[],difficulty:3,keywords:[]},resources:[],searching:false,apiAvailable:false,pptDialogVisible:false,pptStatus:{activeStep:1,status:'processing',percentage:0,message:'',pptUrl:''}}},created(){this.checkApi()},methods:{async checkApi(){try{const r=await this.$http.post('/api/generate-ppt',{topic:'ping',keywords:[],subject:'',difficulty:'1'});const m=(r.data&&r.data.message)||'';this.apiAvailable=!m.includes('not configured')}catch(e){this.apiAvailable=false}},async generatePPT(){if(!this.searchForm.topic){this.$message.warning('Enter topic');return}this.searching=true;this.pptDialogVisible=true;try{const r=await this.$http.post('/api/generate-ppt',{topic:this.searchForm.topic,keywords:this.searchForm.keywords,subject:this.searchForm.subject.join('/'),difficulty:this.searchForm.difficulty});if(r.data.code===0){this.pptStatus.sid=r.data.data.sid;this.pptStatus.message='Submitted. Using local fallback...';await this.generateLocal()}else{this.$message.error(r.data.message||'Failed');if(r.data.message&&r.data.message.includes('quota')){this.$message.info('Quota exceeded, using local');await this.generateLocal()}}}catch(e){this.$message.error('Error');await this.generateLocal()}this.searching=false},async generateLocal(){this.pptStatus.percentage=100;this.pptStatus.status='done';this.pptStatus.message='Local PPT ready';this.pptStatus.pptUrl='#';this.resources.push({id:Date.now(),title:this.searchForm.topic,type:'ppt',difficulty:this.searchForm.difficulty,description:'Local generated: '+this.searchForm.topic})}}}</script>